VALUES
  ('generalpolice-8b7f1efc-moex-00162', 'generalpolice-8b7f1efc', 'generalpolice-8b7f1efc-moex-113-3d2b73b6', 'sub-generalpolice-8b7f1efc-05', NULL, 'single_choice', '關於法規的失效，下列敘述何者正確？', '["法定施行期間經過後，仍須待主管機關公告，始失其效力", "法律不得授權以命令訂定失效日期", "法律之廢止，應經立法院通過，總統公布", "憲法法庭對於違憲之法規，只能宣告定期失效"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:34+00:00", "source_pdf_sha1": "f0c6a23ff7fb", "answer_pdf_sha1": "a74147423676", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "301", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('generalpolice-8b7f1efc-moex-00163', 'generalpolice-8b7f1efc', 'generalpolice-8b7f1efc-moex-113-3d2b73b6', 'sub-generalpolice-8b7f1efc-05', NULL, 'single_choice', '關於信賴保護原則，下列敘述何者錯誤？', '["信賴保護原則為法治國原則的具體實踐，且與法安定性與既得權保障有關", "行政法規倘預先訂定施行期間，不生信賴保護問題", "行政法規之變更與廢止，不生信賴保護之問題", "人民明知行政處分違法，其信賴不值得保護"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:34+00:00", "source_pdf_sha1": "f0c6a23ff7fb", "answer_pdf_sha1": "a74147423676", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "301", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('generalpolice-8b7f1efc-moex-00164', 'generalpolice-8b7f1efc', 'generalpolice-8b7f1efc-moex-113-3d2b73b6', 'sub-generalpolice-8b7f1efc-05', NULL, 'single_choice', '有關保安處分之規定，下列敘述何者正確？', '["中華民國國民如具有外國國籍，即得適用驅逐出境規定", "保安處分於刑之執行完畢後宣告之", "受緩刑之宣告者，應於緩刑期間付保護管束", "感化教育、監護、禁戒、強制工作等保安處分，按其情形得以保護管束代之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:34+00:00", "source_pdf_sha1": "f0c6a23ff7fb", "answer_pdf_sha1": "a74147423676", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "301", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('generalpolice-8b7f1efc-moex-00165', 'generalpolice-8b7f1efc', 'generalpolice-8b7f1efc-moex-113-3d2b73b6', 'sub-generalpolice-8b7f1efc-05', NULL, 'single_choice', '消防官員李四對張三之場所執行消防安檢時指出其設備有缺失之處，張三一時氣憤，便對李四怒罵 道：「臭官員，有什麼了不起！敢罰我的話，以後出門小心點，看到你一次，打一次！」下列敘述何 者正確？', '["張三觸犯刑法第135條第1項妨害公務罪，因為公務員李四係依法執行職務，且張三的行為屬於 脅迫", "張三觸犯刑法第135條第1項妨害公務罪，因為李四係公務員，無論其是否依法執行職務，皆不 得施以脅迫", "張三未觸犯刑法第135條第1項妨害公務罪，因為該罪僅罰強暴行為", "張三未觸犯刑法第135條第1項妨害公務罪，因為消防安檢並非國家公權力的運作行為"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:34+00:00", "source_pdf_sha1": "f0c6a23ff7fb", "answer_pdf_sha1": "a74147423676", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "301", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('generalpolice-8b7f1efc-moex-00166', 'generalpolice-8b7f1efc', 'generalpolice-8b7f1efc-moex-113-3d2b73b6', 'sub-generalpolice-8b7f1efc-05', NULL, 'single_choice', '依我國著作權法規定，下列何者會侵害他人之著作財產權？', '["國立大學之教師，為學校授課需要而將他人整本教科書上傳至數位教學平台，供選課學生下載閱讀", "經濟部智慧財產局，因研擬新法所需，認有必要將他人著作列為內部參考資料時，得在合理範圍 內，重製他人之學術論文", "圖書館基於保存資料之必要，而以掃描之方式重製其所收藏的珍稀書籍", "國家圖書館為製作期刊論文索引系統供公眾查詢，而重製刊載於期刊中的學術論文所附之摘要"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:34+00:00", "source_pdf_sha1": "f0c6a23ff7fb", "answer_pdf_sha1": "a74147423676", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "301", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('generalpolice-8b7f1efc-moex-00167', 'generalpolice-8b7f1efc', 'generalpolice-8b7f1efc-moex-113-3d2b73b6', 'sub-generalpolice-8b7f1efc-05', NULL, 'single_choice', '甲因侵權行為而與被害人乙和解，約定甲於3日內對乙賠償新臺幣（以下同）20萬元。嗣後，甲持 以10元硬幣湊滿的20萬元向乙為給付。甲的給付行為違反：', '["權利濫用禁止原則", "私法自治原則", "契約自由原則", "誠實信用原則"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:34+00:00", "source_pdf_sha1": "f0c6a23ff7fb", "answer_pdf_sha1": "a74147423676", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "301", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('generalpolice-8b7f1efc-moex-00168', 'generalpolice-8b7f1efc', 'generalpolice-8b7f1efc-moex-113-3d2b73b6', 'sub-generalpolice-8b7f1efc-05', NULL, 'single_choice', '下列何者之性質非屬形成權？', '["抗辯權", "撤銷權", "解除權", "終止權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:34+00:00", "source_pdf_sha1": "f0c6a23ff7fb", "answer_pdf_sha1": "a74147423676", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "301", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('generalpolice-8b7f1efc-moex-00169', 'generalpolice-8b7f1efc', 'generalpolice-8b7f1efc-moex-113-3d2b73b6', 'sub-generalpolice-8b7f1efc-05', NULL, 'single_choice', '甲男自小生活在大家族中，家族親戚往來頻繁。依現行法，甲男不得與何人結婚？', '["甲的堂嫂的妹妹", "甲的堂伯父的女兒", "甲的表姑媽收養的女兒", "甲的表姑媽收養的兒子"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:34+00:00", "source_pdf_sha1": "f0c6a23ff7fb", "answer_pdf_sha1": "a74147423676", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "301", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('generalpolice-8b7f1efc-moex-00170', 'generalpolice-8b7f1efc', 'generalpolice-8b7f1efc-moex-113-3d2b73b6', 'sub-generalpolice-8b7f1efc-05', NULL, 'single_choice', '依民法之規定，下列敘述何者正確？', '["如民眾出示其為不識字之證明者，其指印或十字，與其親自簽名之效力相同", "關於一定之數量，同時以兩種文字與數字號碼以上表示者，兩者如不符合時，如法院不能決定何者 為當事人之原意，應以當事人之母國文字為準", "民眾於銀行、信用合作社或農漁會進行交易時，如用印鑑章代簽名者，其用印鑑章之效力大於本人 親自簽名", "依法律之規定，有使用文字之必要者，得不由本人自寫，但必須親自簽名"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:34+00:00", "source_pdf_sha1": "f0c6a23ff7fb", "answer_pdf_sha1": "a74147423676", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "301", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('generalpolice-8b7f1efc-moex-00171', 'generalpolice-8b7f1efc', 'generalpolice-8b7f1efc-moex-113-3d2b73b6', 'sub-generalpolice-8b7f1efc-05', NULL, 'single_choice', '下列何者非信賴保護原則之要件？', '["信賴基礎", "信賴行為", "值得保護之信賴", "無不當聯結"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:34+00:00", "source_pdf_sha1": "f0c6a23ff7fb", "answer_pdf_sha1": "a74147423676", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "301", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政警察人員"}'::jsonb, NULL)
